1	/**
2	 * Givens template interpolation — isolated module.
3	 *
4	 * Handles ${...} expression scanning, parsing, resolution, and stringification.
5	 * Designed to be replaceable with an external templating library if needed.
6	 *
7	 * Supported syntax:
8	 *   ${expr}         — interpolate expression; whole-value or inline
9	 *   \${expr}        — escape: produces literal "${expr}" in output, not interpolated
10	 */
11	
12	/** Regex to find all ${...} expressions in a string (non-escaped). */
13	const TEMPLATE_EXPR_RE = /\$\{([^}]+)\}/g;
14	
15	/** Regex to detect escaped \${ sequences. */
16	const ESCAPED_TEMPLATE_RE = /\\\$\{/g;
17	
18	/** Sentinel used during interpolation to protect escaped sequences from the regex. */
19	const ESCAPE_SENTINEL = '\x00ESCAPED_DOLLAR_BRACE\x00';
20	
21	/**
22	 * Sentinel value returned by the `resolve` callback to indicate that an
23	 * expression should be left in place (not interpolated).
24	 *
25	 * Used by spawn-time resolution to preserve ${yields.*} expressions for
26	 * the later run-time resolution phase.
27	 */
28	export const SKIP: unique symbol = Symbol('SKIP');
29	
30	/**
31	 * Resolve a dot-path against a root value.
32	 *
33	 * @example
34	 * resolveDotPath({ a: { b: 42 } }, 'a.b') → 42
35	 * resolveDotPath({ a: 1 }, 'a.b.c') → undefined
36	 *
37	 * Returns `undefined` if any segment along the path is nullish or not an object.
38	 */
39	export function resolveDotPath(root: unknown, path: string): unknown {
40	  let current: unknown = root;
41	  for (const segment of path.split('.')) {
42	    if (current === null || current === undefined || typeof current !== 'object') {
43	      return undefined;
44	    }
45	    current = (current as Record<string, unknown>)[segment];
46	  }
47	  return current;
48	}
49	
50	/**
51	 * Convert a resolved value to a string for inline interpolation.
52	 *
53	 * - `undefined` → `''` (empty string)
54	 * - `string` → as-is
