    function renderBreadcrumb() {
      const bar = document.getElementById('breadcrumb-bar');
      if (!scopedRootId) {
        bar.style.display = 'none';
        bar.innerHTML = '';
        return;
      }
      const path = ancestorPath(forest, scopedRootId);
      bar.innerHTML = '';
      bar.style.display = '';

      const showAll = document.createElement('a');
      showAll.textContent = 'Show all';
      showAll.addEventListener('click', () => {
        scopedRootId = null;
        updateUrl({ root: null });
        renderTree();
      });
      bar.appendChild(showAll);

      for (let i = 0; i < path.length; i++) {
        const node = path[i];
        const sep = document.createElement('span');
        sep.className = 'sep';
        sep.textContent = '›';
        bar.appendChild(sep);

        if (i === path.length - 1) {
          const cur = document.createElement('span');
          cur.className = 'current';
          cur.textContent = node.click.goal;
          bar.appendChild(cur);
        } else {
          const a = document.createElement('a');
          a.textContent = node.click.goal;
          a.addEventListener('click', () => {
            scopedRootId = node.click.id;
            updateUrl({ root: node.click.id });
            renderTree();
          });
          bar.appendChild(a);
        }
