function renderBreadcrumb() {
  const el = document.getElementById('breadcrumb');
  if (!el) return;
  const segments = buildBreadcrumbSegments(forest, scopedRootId);
  if (!segments) {
    el.style.display = 'none';
    el.innerHTML = '';
    return;
  }
  el.style.display = 'block';

  const parts = [];
  parts.push('<span class="breadcrumb-segment" data-breadcrumb-id="">Show all</span>');

  for (const a of segments.ancestors) {
    parts.push('<span class="breadcrumb-sep">/</span>');
    parts.push(
      `<span class="breadcrumb-segment" data-breadcrumb-id="${escAttr(a.id)}">${escHtml(a.goal ?? a.id)}</span>`,
    );
  }

  parts.push('<span class="breadcrumb-sep">/</span>');
  if (segments.current) {
    parts.push(`<span class="breadcrumb-current">${escHtml(segments.current.goal ?? segments.current.id)}</span>`);
  } else if (segments.missingId) {
    parts.push(
      `<span class="breadcrumb-current"><code>${escHtml(segments.missingId)}</code> (not found)</span>`,
    );
  }

  el.innerHTML = parts.join('');

  el.querySelectorAll('[data-breadcrumb-id]').forEach((seg) => {
    seg.addEventListener('click', () => {
      const id = seg.getAttribute('data-breadcrumb-id');
      focusSubtree(id ? id : null);
    });
  });
}

