#!/usr/bin/env python3
"""Zoom in on Phase C (post-compaction-2) turns."""
import json
from pathlib import Path
TRANSCRIPT = Path("/home/vscode/.claude/projects/-workspace-vibers-tmp-nexus-drafts-nexus-draft-mo1wak9c-9415c244/99c46df8-e422-4efa-b8d5-aec28d9f7089.jsonl")
seen_tool_ids = set()
records = []  # (ts, tool_name, input, text)
for line in TRANSCRIPT.read_text().splitlines():
    if not line.strip(): continue
    try: e = json.loads(line)
    except: continue
    if e.get("type") != "assistant": continue
    ts = e.get("timestamp")
    content = e.get("message", {}).get("content", [])
    for b in content:
        if b.get("type") == "tool_use":
            tid = b.get("id")
            if tid in seen_tool_ids: continue
            seen_tool_ids.add(tid)
            records.append((ts, b.get("name"), b.get("input", {}), None))
        elif b.get("type") == "text":
            if b.get("text", "").strip():
                records.append((ts, "TEXT", None, b.get("text")))

# Filter to compact-2 onward (after 2026-04-16T20:00:30Z)
phase_c_records = [r for r in records if r[0] >= "2026-04-16T20:00:30"]
print(f"Phase C records: {len(phase_c_records)}")
for ts, nm, inp, txt in phase_c_records:
    if nm == "TEXT":
        print(f"\n{ts} [TEXT]\n{txt[:600]}")
    elif nm == "Read":
        print(f"\n{ts} [Read] {inp.get('file_path')}")
    elif nm == "Write":
        fp = inp.get("file_path", "?").split("/")[-1]
        ct = inp.get("content", "")
        print(f"\n{ts} [Write {fp}] ({len(ct)} chars)")
        print(ct[:300] + "..." if len(ct) > 300 else ct)
    elif nm == "Edit":
        fp = inp.get("file_path", "?").split("/")[-1]
        print(f"\n{ts} [Edit {fp}]")
    elif nm == "Bash":
        print(f"\n{ts} [Bash] {inp.get('command', '')[:200]}")
    elif nm == "TodoWrite":
        todos = inp.get("todos", [])
        if isinstance(todos, list):
            print(f"\n{ts} [TodoWrite]")
            for td in todos:
                if isinstance(td, dict):
                    c = td.get('content', '')
                    s = td.get('status', '')
                    print(f"  [{s}] {c}")
        else:
            print(f"\n{ts} [TodoWrite] (non-list)")
    else:
        print(f"\n{ts} [{nm}]")
